from pynput import keyboard

# Game dimensions
GRID_SIZE = 20
SNAKE_START_LENGTH = 3

# Snake colors
SNAKE_COLOR = (0, 255, 0)
FOOD_COLOR = (255, 0, 0)
BACKGROUND_COLOR = (0, 0, 0)

# Snake movement directions
UP = 0
RIGHT = 1
DOWN = 2
LEFT = 3

class Snake:
    def __init__(self):
        self.body = [(GRID_SIZE//2, GRID_SIZE//2)]
        self.direction = RIGHT
        self.grow = False

    def move(self):
        head = self.body[-1]
        if self.direction == UP:
            new_head = (head[0], head[1] - 1)
        elif self.direction == RIGHT:
            new_head = (head[0] + 1, head[1])
        elif self.direction == DOWN:
            new_head = (head[0], head[1] + 1)
        else:
            new_head = (head[0] - 1, head[1])

        if self.grow:
            self.grow = False
        else:
            self.body.pop(0)

        self.body.append(new_head)

    def change_direction(self, direction):
        self.direction = direction

    def collides_with_self(self):
        head = self.body[-1]
        return head in self.body[:-1]

    def collides_with_edge(self):
        head = self.body[-1]
        return head[0] < 0 or head[0] >= GRID_SIZE or head[1] < 0 or head[1] >= GRID_SIZE

class Game:
    def __init__(self):
        self.snake = Snake()
        self.food = self.generate_food()

    def generate_food(self):
        x = random.randint(0, GRID_SIZE - 1)
        y = random.randint(0, GRID_SIZE - 1)
        return (x, y)

    def draw(self):
        os.system('cls' if os.name == 'nt' else 'clear')
        for y in range(GRID_SIZE):
            for x in range(GRID_SIZE):
                if (x, y) in self.snake.body:
                    print(f"\033[{SNAKE_COLOR[1]};{SNAKE_COLOR[0]};{SNAKE_COLOR[2]}m#\033[0m", end="")
                elif (x, y) == self.food:
                    print(f"\033[{FOOD_COLOR[1]};{FOOD_COLOR[0]};{FOOD_COLOR[2]}m@\033[0m", end="")
                else:
                    print("\033[{};{};{}m.\033[0m".format(BACKGROUND_COLOR[1], BACKGROUND_COLOR[0], BACKGROUND_COLOR[2]), end="")
            print()

    def check_collision(self):
        return self.snake.collides_with_self() or self.snake.collides_with_edge()

    def check_food(self):
        head = self.snake.body[-1]
        if head == self.food:
            self.snake.grow = True
            self.food = self.generate_food()

    def run(self):
        on_press = None

        def on_press(key):
            try:
                if key == keyboard.Key.up:
                    game.snake.change_direction(UP)
                elif key == keyboard.Key.right:
                    game.snake.change_direction(RIGHT)
                elif key == keyboard.Key.down:
                    game.snake.change_direction(DOWN)
                elif key == keyboard.Key.left:
                    game.snake.change_direction(LEFT)
